import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XssFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by encoding it before including it in the HTML response
        String encodedUserInput = null;
        try {
            encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Encoding error: " + e.getMessage());
            // Handle encoding error as needed
        }

        String htmlResponse = "<html><body>Welcome, " + encodedUserInput + "</body></html>";

        System.out.println(htmlResponse);
    }
}

